/* CSS will be added here */
:root{

  --primary-color:#0d6efd;
  --secondary-color:#ff6b00;

  --success-color:#16a34a;
  --danger-color:#dc2626;
  --warning-color:#f59e0b;

  --white:#ffffff;
  --black:#000000;

  --text-color:#333333;
  --text-light:#666666;

  --bg-color:#f5f5f5;
  --card-bg:#ffffff;

  --border-color:#dddddd;

  --header-height:70px;

  --container-width:1280px;

  --transition:0.3s ease;

  --radius:8px;

  --shadow:0 5px 15px rgba(0,0,0,.08);

}/* ===========================
   CSS RESET
=========================== */

*{
    margin:0;
    padding:0;
    box-sizing:border-box;
}

html{
    scroll-behavior:smooth;
}

body{
    font-family:Arial, Helvetica, sans-serif;
    font-size:16px;
    color:var(--text-color);
    background:var(--bg-color);
    line-height:1.6;
}

a{
    color:inherit;
    text-decoration:none;
}

img{
    max-width:100%;
    display:block;
}

ul,
ol{
    list-style:none;
}

button,
input,
textarea{
    font:inherit;
    outline:none;
    border:none;
}

.container{
    width:100%;
    max-width:var(--container-width);
    margin:auto;
    padding:0 15px;
}
